main.script:
		document.addEventListener( "DOMContentLoaded", function() {
			jQuery(function() {
				//if(jQuery('cwf-hdr-searchbox-container').length > 0) {

					if (algolia.indices.searchable_posts === undefined && jQuery('.admin-bar').length > 0) {
						alert('It looks like you haven\'t indexed the searchable posts index. Please head to the Indexing page of the Algolia Search plugin and index it.');
					}

					/* Instantiate instantsearch.js */
					var search = instantsearch({
						appId: algolia.application_id,
						apiKey: algolia.search_api_key,
						indexName: algolia.indices.searchable_posts.name,
						urlSync: {
							mapping: {'q': 's'},
							trackedParameters: ['query']
						}
					});

					/* Search box widget */
					search.addWidget(
						instantsearch.widgets.searchBox({
							container: '#cwf-hdr-search-input',
							placeholder: 'Search for...',
							wrapInput: false,
							poweredBy: algolia.powered_by_enabled
						})
					);

					search.addWidget({
						init: function(options){
							//options.helper.addFacetRefinement('wpml.language_code', wpml_current_language);
						}
					});

					/* Stats widget */
					search.addWidget(
						instantsearch.widgets.stats({
							container: '#algolia-stats'
						})
					);

					/* Hits widget */
					search.addWidget(
						instantsearch.widgets.hits({
							container: '#algolia-hits',
							hitsPerPage: 8,
							templates: {
								empty: wp.template('instantsearch-empty'),
								item: wp.template('instantsearch-hit')
							},
                            transformData: function (hit) {
                                if(hit.post_type == 'events') {
                                    if(hit['event_start_date'] > Math.floor(Date.now() / 1000)) {
                                        hit['date_text'] = 'Upcoming';
                                        hit['date_class'] = 'date--upcoming';
                                    } else {
                                        hit['date_text'] = 'Event has passed';
                                        hit['date_class'] = 'date--passed';
                                    }
                                }
                                return hit;
                            }
						})
					);

					/* Pagination widget */
					search.addWidget(
						instantsearch.widgets.pagination({
							container: '#algolia-pagination',
							showFirstLast: false,
                            padding: 2
						})
					);

					/* Post types menu widget */
					search.addWidget(
						instantsearch.widgets.menu({
							container: '#facet-post-types',
							attributeName: 'post_type_label',
							sortBy: [ 'count:desc', 'name:asc'],
                            limit: 10,
                            templates: {
                                item: wp.template('instantsearch-menu')
                            },
						})
                    );

                    search.addWidget(
                        instantsearch.widgets.clearAll({
                            container: '#clear-all',
                            cssClasses: {
                                link: 'ais-clear-all--link__active'
                            },
                            templates: {
                                link: 'Everything'
                            },
                            autoHideContainer: false
                        })
                    );

					/* Start */
					search.start();

                    jQuery('#algolia-search-box input').attr('type', 'search').select();
                    jQuery(document).keypress(
                    function(event){
                        if (event.which == '13') {
                            event.preventDefault();
                        }
                    });

                    search.on('render', function(){
                        jQuery('.ais-menu--link').click(function(menulink){
                            jQuery('.ais-clear-all--link').removeClass('ais-clear-all--link__active');
                            if(jQuery(menulink.currentTarget).parent().parent().hasClass('ais-menu--item__active')) {
                                jQuery('.ais-clear-all--link').addClass('ais-clear-all--link__active');
                            }
                        });
                        jQuery('.ais-clear-all--link').click(function(){
                            jQuery('.ais-clear-all--link').addClass('ais-clear-all--link__active');
                        });
                    });



                //}
			});
		});

